                                            <path class="pk-p-eye" d="M122.3 118.5c-3.8 0-6.9-3.1-6.9-6.9V97.1c0-3.8 3.1-6.9 6.9-6.9 3.8 0 6.9 3.1 6.9 6.9v14.6c0 3.8-3.1 6.8-6.9 6.8z" fill="#444" stroke="#444" stroke-width="5"/>
